mapper.select:
SELECT CASE WHEN DOCGB = '200' THEN '거래명세서' WHEN DOCGB = '700' THEN '상담실초대' END AS docgbnm, A.SENDYMD as sendymd, A.SENDNO as sendno, A.USERID as userid, C.USERNM as usernm, A.SEND_DATE AS senddate, A.CUSTCD as custcd, B.CUSTNM as custnm, A.EMAIL as email, A.SEND_EMAIL AS sendemail, A.ATTACH_URL AS attachurl, A.SCHEDULE_TYPE AS scheduletype, A.RESERVED_DATE AS reserveddate, A.RESERVED_H AS reservedh, A.CONN_INFO AS conninfo, A.SENDYN as sendyn FROM MAIL_SEND_HIST_TBL A LEFT JOIN HABA020T_TBL B ON A.CMPYCD = B.CMPYCD AND A.CUSTCD = B.CUSTCD LEFT JOIN HABA920T_TBL C ON A.CMPYCD = C.CMPYCD AND A.USERID = C.USERID WHERE A.CMPYCD = #{cmpycd} AND A.SENDYMD BETWEEN #{fromdt} AND #{todt} AND A.SENDYN = #{sendyn}
AND A.DOCGB = #{docgb}
AND B.CUSTNM LIKE CONCAT('%', #{custnm}, '%')
ORDER BY A.SEND_DATE DESC
